sp_widget.client_script:
api.controller = function($scope) {
    /* widget controller */
    var c = this;

    c.onCancel = function() {
        $scope.$parent.$parent.$dismiss();
    };

    c.enableSubmitButton = function() {
        if (c.data.newCancellationReason === undefined) {
            c.data.isSubmitButtonDisabled = true;
        } else {
            c.data.isSubmitButtonDisabled = c.data.newCancellationReason.length === 0;
        }
    };

    c.onSubmit = function() {
        c.data.submit = true;
        $scope.server.update().then(function() {
            $scope.$parent.$parent.$dismiss();
        });

    };

};

sp_widget.script:
