// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// WIDGET BASE: Tasker Modal - Delete Task
//------------------------------------------------------------------------------------------------------------------------
// 2.7.0 | 2021-09-22 | mmcc | STRY0108861 - DIA- Cancel from Top Task Notification 
//											In HTML, all new. var's msgBody# coded to match AC line #,
//											  Submit button disabled while var newCancellationReason
//											  length = 0.
//											In CSS, No CSS here, put in Tasker Theme. 
//											In Service script, all new. Grouped code into functions.
//											In Client controller, all new. Grouped code into functions.
//                                          Changes in HTML, CSS, Server script and Client controller
// 2.7.0 | 2021-10-8 | mmcc | STRY0109110 - Draft Scheduled Tasks – UI – Delete Modal- Add Descendant tasks count
//											In Service script, Using TaskerHelpers().getDescendantsCount()
//                                          Changes in Server script
// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
//											In Service script, Made params.countType test for 'EXCLUDE_CLOSE'; 
//											 do not count Completed, Closed Incomplete and Cancelled tasks
//                                          Changes in Server script
// 2.8.0 | 2022-08-14 | raj  |  STRY0125927 - All Mark Complete modals- Add info message "Marking complete will delete Draft Tasks"
//                                          Changes in Server script and HTML
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options) {
    var tableRouteTaskInstance = 'x_153465_discovert_route_task_instance';

    main();

    function main() {
        if (input) {
            if (input.submit == true) {
                // run cancel step
				var grTasksCancel = new GlideRecord(tableRouteTaskInstance);
                if (grTasksCancel.get(input.taskSysId)) {

					var gdt2 = new GlideDateTime();
                    new Task_uiAction().uiAction_CancelTasks(grTasksCancel, input.newCancellationReason, gdt2);
                }
            } else {
                // copy to data[name] from input[name] || option[name]
                _optCopy(['cancellationReason', 'taskSysId']);
                _buildMessages();
                _setDataDefaults();
            }
        }
    }

	function _buildMessages() {
		// STRY0125927
		_getDescendantsCount();
		data.cancelButtonText = gs.getMessage('cancel');
		data.submitButtonText = gs.getMessage('Tasker - Button - Cancel Task(s)');
		data.submitButtonTitle = gs.getMessage('Tasker - Sets the State to Cancelled');

		data.msgBody2 = gs.getMessage('Warning');
		// STRY0125927
		data.msgBody3 = gs.getMessage('Tasker - Warning: You have {0} open subtasks', [data.activeDescendantsCount.toString()]);
		data.msgBody4 = gs.getMessage('Tasker - By cancelling this task, you will automatically cancel the subtasks as well');

		// STRY0125927
		data.msgDraftCount = gs.getMessage('Tasker - You have {0} draft tasks', [data.draftDescendantsCount.toString()]);
		data.msgDraftInfo = gs.getMessage('Tasker - This will automatically delete ALL draft subtasks as well');

		data.msgBody5 = gs.getMessage('Tasker - Are you sure you would like to continue?');
		data.msgBody6 = gs.getMessage('Tasker - Cancellation Reason');

		data.msgBody7 = gs.getMessage('Type your reason here');
	}

	function _getDescendantsCount() {
		// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
		var details = {
			taskSysId: data.taskSysId,
			countType: 'EXCLUDE_CLOSE'
		};

		var taskerHelpers = new TaskerHelpers();
		// STRY0125927
		var totalDescendantsCount = taskerHelpers.getDescendantsCount(details);
		var draftDescendantsCount = taskerHelpers.getDraftDescendantsCount(data.taskSysId);
		data.activeDescendantsCount = totalDescendantsCount - draftDescendantsCount;
		data.draftDescendantsCount = draftDescendantsCount;

	}


    // copy to data from input or options
    function _optCopy(names) {
        names.forEach(function(name) {
            data[name] = input[name] || options[name];
        });
    }

    function _setDataDefaults() {
        data.isSubmitButtonDisabled = true;
        data.submit = false;
        data.newCancellationReason = data.cancellationReason;
        if (data.newCancellationReason === undefined) {
            data.isSubmitButtonDisabled = true;
        } else {
            data.isSubmitButtonDisabled = data.newCancellationReason.length === 0;
        }
    }
})($sp, input, data, options);
